import { Component, OnInit } from '@angular/core';
import { ActivatedRoute } from '@angular/router';
import { HackathonService } from '../../../../core/services/hackathon.service';
import { SupportRequestService, SupportRequest } from '../../../../core/services/support-request.service';
import { ReportService, Report } from '../../../../core/services/report.service';
import { HackathonSummaryDTO } from '../../../../core/models/hackathon.model';

@Component({
  selector: 'app-mentor-hackathon-dashboard',
  templateUrl: './mentor-hackathon-dashboard.component.html',
  styleUrls: ['./mentor-hackathon-dashboard.component.scss']
})
export class MentorHackathonDashboardComponent implements OnInit {
  hackathonId: string | null = null;
  hackathon: HackathonSummaryDTO | null = null;
  supportRequests: SupportRequest[] = [];
  reports: Report[] = [];
  participants: any[] = [];
  activeTab: 'support' | 'reports' = 'support';
  isLoading = true;

  // New report form state
  showReportModal = false;
  reportForm = {
    teamId: '',
    descrizione: ''
  };

  constructor(
    private route: ActivatedRoute,
    private hackathonService: HackathonService,
    private supportService: SupportRequestService,
    private reportService: ReportService
  ) { }

  ngOnInit(): void {
    this.route.paramMap.subscribe(params => {
      this.hackathonId = params.get('id');
      if (this.hackathonId) {
        this.loadData();
      }
    });
  }

  loadData(): void {
    this.isLoading = true;
    if (!this.hackathonId) return;

    this.hackathonService.getHackathonById(this.hackathonId).subscribe({
      next: (h) => {
        this.hackathon = h;
        this.loadSupportRequests();
        this.loadReports();
        this.loadParticipants();
        this.isLoading = false;
      },
      error: (err) => {
        console.error('Error loading hackathon details:', err);
        this.isLoading = false;
        alert('Errore nel caricamento dell\'hackathon.');
      }
    });
  }

  loadSupportRequests(): void {
    if (!this.hackathonId) return;
    this.supportService.getRequestsByHackathon(this.hackathonId).subscribe(reqs => {
      this.supportRequests = reqs;
    });
  }

  loadReports(): void {
    if (!this.hackathonId) return;
    this.reportService.getReportsByHackathon(this.hackathonId).subscribe(reps => {
      this.reports = reps;
    });
  }

  loadParticipants(): void {
    if (!this.hackathonId) return;
    this.hackathonService.getParticipants(this.hackathonId).subscribe(teams => {
      this.participants = teams;
    });
  }

  proposeCall(req: SupportRequest): void {
    const link = prompt('Inserisci il link della call (Google Meet/Webex):');
    const data = prompt('Inserisci data e ora della call (es: 2026-03-20T10:00:00):');

    if (link && data) {
      this.supportService.proposeCall(req.id, link, data).subscribe({
        next: () => {
          alert('Call proposta con successo!');
          this.loadSupportRequests();
        },
        error: (err) => alert('Errore: ' + (err.error?.message || err.message))
      });
    }
  }

  openReportModal(): void {
    this.showReportModal = true;
    this.reportForm = { teamId: '', descrizione: '' };
  }

  closeReportModal(): void {
    this.showReportModal = false;
  }

  submitReport(): void {
    if (!this.hackathonId || !this.reportForm.teamId || !this.reportForm.descrizione.trim()) {
      alert('Per favore compila tutti i campi.');
      return;
    }

    this.reportService.createReport({
      idHackathon: this.hackathonId,
      idTeam: this.reportForm.teamId,
      descrizione: this.reportForm.descrizione
    }).subscribe({
      next: () => {
        alert('Segnalazione inviata con successo!');
        this.closeReportModal();
        this.loadReports();
      },
      error: (err) => alert('Errore: ' + (err.error?.message || err.message))
    });
  }
}
<div class="dashboard-container" *ngIf="!isLoading; else loading">
  <header class="dashboard-header" *ngIf="hackathon">
    <div class="header-content">
      <div class="status-chip">{{ hackathon.stato }}</div>
      <h1 class="hackathon-title">👨‍🏫 Mentoring: {{ hackathon.nome }}</h1>
      <p class="hackathon-sub">{{ hackathon.luogo }} · {{ hackathon.premioInDenaro | currency:'EUR' }}</p>
    </div>

    <div class="header-actions">
      <button class="btn-primary" (click)="openReportModal()">
        <span>🚩 Nuova Segnalazione</span>
      </button>
    </div>
  </header>

  <div class="tabs">
    <button class="tab" [class.active]="activeTab === 'support'" (click)="activeTab = 'support'">
      📞 Richieste Supporto ({{ supportRequests.length }})
    </button>
    <button class="tab" [class.active]="activeTab === 'reports'" (click)="activeTab = 'reports'">
      📊 Segnalazioni ({{ reports.length }})
    </button>
  </div>

  <div class="tab-content">
    <!-- Support Requests Tab -->
    <div *ngIf="activeTab === 'support'">
      <div class="card-grid" *ngIf="supportRequests.length > 0; else noRequests">
        <div class="submission-card" *ngFor="let req of supportRequests">
          <div class="card-header">
            <h3>{{ req.nomeTeam }}</h3>
            <span class="date">{{ req.dataRichiesta | date:'short' }}</span>
          </div>
          <p class="desc">{{ req.descrizione }}</p>

          <div class="call-info" *ngIf="req.linkCall">
            <p><strong>✅ Call Fissata:</strong> <a [href]="req.linkCall" target="_blank">{{ req.linkCall }}</a></p>
            <p><strong>📅 Data:</strong> {{ req.dataCall | date:'short' }}</p>
          </div>

          <div class="actions">
            <button class="btn-eval" (click)="proposeCall(req)">
              {{ req.linkCall ? '🔄 Modifica Call' : '📞 Proponi Call' }}
            </button>
          </div>
        </div>
      </div>
      <ng-template #noRequests>
        <div class="empty-state">Nessuna richiesta di supporto per questo hackathon.</div>
      </ng-template>
    </div>

    <!-- Reports Tab -->
    <div *ngIf="activeTab === 'reports'">
      <div class="ranking-list" *ngIf="reports.length > 0; else noReports">
        <div class="ranking-item" *ngFor="let r of reports">
          <div class="report-content">
            <div class="report-header">
              <span class="team-name">🚩 Team: {{ r.nomeTeam }}</span>
              <span class="date">{{ r.dataSegnalazione | date:'short' }}</span>
            </div>
            <p class="desc">{{ r.descrizione }}</p>
            <small class="mentor">Mentore: {{ r.nomeMentore }}</small>
          </div>
        </div>
      </div>
      <ng-template #noReports>
        <div class="empty-state">Nessuna segnalazione inviata.</div>
      </ng-template>
    </div>
  </div>

  <!-- Report Modal -->
  <div class="modal-overlay" *ngIf="showReportModal">
    <div class="modal-content">
      <div class="modal-header">
        <h2>🚩 Nuova Segnalazione</h2>
        <button class="close-btn" (click)="closeReportModal()">×</button>
      </div>

      <div class="modal-body">
        <div class="form-group">
          <label for="teamSelect">Seleziona Team</label>
          <select id="teamSelect" [(ngModel)]="reportForm.teamId" class="form-control">
            <option value="" disabled selected>Seleziona un team...</option>
            <option *ngFor="let team of participants" [value]="team.id">
              {{ team.nomeTeam }}
            </option>
          </select>
        </div>

        <div class="form-group">
          <label for="description">Descrizione Segnalazione</label>
          <textarea 
            id="description" 
            [(ngModel)]="reportForm.descrizione" 
            rows="5" 
            class="form-control"
            placeholder="Descrivi il motivo della segnalazione..."></textarea>
        </div>
      </div>

      <div class="modal-footer">
        <button class="btn-secondary" (click)="closeReportModal()">Annulla</button>
        <button class="btn-primary-dark" (click)="submitReport()">Invia Segnalazione</button>
      </div>
    </div>
  </div>
</div>

<ng-template #loading>
  <div class="loading-state">
    <div class="spinner"></div>
    <p>Caricamento dashboard mentore...</p>
  </div>
</ng-template>
